using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);
var errors = new List<(string Project, string Code, string File, int Line, string Message)>();
var warnings = new List<(string Project, string Code, string File, int Line, string Message)>();

build.VisitAllChildren<Error>(e => {
    var project = GetProjectName(e);
    errors.Add((project, e.Code ?? "", e.File ?? "", e.LineNumber, e.Message ?? e.Text ?? ""));
});

build.VisitAllChildren<Warning>(w => {
    var project = GetProjectName(w);
    warnings.Add((project, w.Code ?? "", w.File ?? "", w.LineNumber, w.Message ?? w.Text ?? ""));
});

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

foreach (var group in errors.GroupBy(e => e.Project))
{
    Console.WriteLine($"--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        Console.WriteLine($"  [{e.Code}] {e.File}({e.Line}): {e.Message}");
    }
    Console.WriteLine();
}

Console.WriteLine("=== BUILD WARNINGS (first 30) ===");
foreach (var w in warnings.Take(30))
{
    Console.WriteLine($"  [{w.Code}] {w.Project}: {w.File}({w.Line}): {w.Message}");
}

string GetProjectName(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name ?? "unknown";
        if (current is Target t && t.Parent is Project tp) return tp.Name ?? "unknown";
        current = current.Parent;
    }
    return "unknown";
}
